import{_ as t,o,c as r,a2 as d}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"VitePress 이관 — Research (Phase 0)","description":"","frontmatter":{"title":"VitePress 이관 — Research (Phase 0)","feature_id":"007","created":"2026-06-01 22:12 (KST)"},"headers":[],"relativePath":"specs/007-vitepress-docs-migration/research.md","filePath":"specs/007-vitepress-docs-migration/research.md","lastUpdated":null}'),s={name:"specs/007-vitepress-docs-migration/research.md"};function i(a,e,c,l,n,u){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="research-문서-저널-사이트-vitepress-이관" tabindex="-1">Research: 문서/저널 사이트 VitePress 이관 <a class="header-anchor" href="#research-문서-저널-사이트-vitepress-이관" aria-label="Permalink to &quot;Research: 문서/저널 사이트 VitePress 이관&quot;">​</a></h1><p>spec Clarifications 로 핵심 결정(저널 자동 인덱스 · 사이드바 자동생성 · strict 빌드 · <code>/blog/</code>)은 이미 확정됐다. 여기서는 그 결정을 <strong>VitePress 에서 어떻게 실현하는가</strong>에 대한 기술 조사 결과를 정리한다. 미해결(NEEDS CLARIFICATION) 없음.</p><h2 id="r-1-docusaurus-→-vitepress-마크다운-호환성-콘텐츠-정제" tabindex="-1">R-1. Docusaurus → VitePress 마크다운 호환성 / 콘텐츠 정제 <a class="header-anchor" href="#r-1-docusaurus-→-vitepress-마크다운-호환성-콘텐츠-정제" aria-label="Permalink to &quot;R-1. Docusaurus → VitePress 마크다운 호환성 / 콘텐츠 정제&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문은 표준 Markdown 으로 그대로 이관하되, MDX 전용 구문만 제거/대체한다. 정제 대상은 (a) <code>{/* truncate */}</code> MDX 주석(저널 10편), (b) <code>vugrid-integration.md</code> 의 <code>import</code>/<code>&lt;VuGrid/&gt;</code> JSX, (c) 절대경로 내부 링크.</li><li><strong>Rationale</strong>: <ul><li><code>:::tip</code> / <code>:::warning</code> 등 컨테이너는 <strong>Docusaurus·VitePress 둘 다 지원</strong>해 수정 불필요(저널 1편에 사용).</li><li>VitePress 는 MDX 가 아닌 markdown-it 기반이라 JSX 임포트·컴포넌트 태그를 렌더하지 못한다 → JSX 는 반드시 제거하거나 Vue/정적으로 대체.</li><li><code>{/* ... */}</code> 는 MDX 주석. VitePress 에선 일반 텍스트로 노출되므로 제거. 저널 요약(목록 카드)은 frontmatter(<code>description</code>/제목)에서 취하므로 truncate 마커가 불필요.</li><li>절대경로(<code>/specs/...</code>, <code>/journal</code>)는 <code>base=/blog/</code> 와 결합 시 깨질 수 있어 상대경로 또는 VitePress 규칙 경로로 교정(strict 빌드가 잔여를 잡아냄).</li></ul></li><li><strong>Alternatives considered</strong>: <ul><li>MDX 플러그인 도입 → VitePress 비표준, 참조 프로젝트와 형태 어긋남. 기각.</li><li>vugrid 라이브 임베드를 Vue 컴포넌트로 재구현 → FR-13 합의(단순화)와 충돌, 범위 초과. 기각(정적 스크린샷 + 링크).</li></ul></li></ul><h2 id="r-2-mermaid-렌더링" tabindex="-1">R-2. mermaid 렌더링 <a class="header-anchor" href="#r-2-mermaid-렌더링" aria-label="Permalink to &quot;R-2. mermaid 렌더링&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>vitepress-plugin-mermaid</code> + <code>mermaid</code> 를 추가하고 <code>config.mts</code> 를 <code>withMermaid()</code> 로 래핑한다. 기존 <code>```mermaid</code> 코드펜스 유지.</li><li><strong>Rationale</strong>: VitePress 는 mermaid 비내장. 저널 3편 + 다수 spec(plan 포함)이 mermaid 를 쓰므로 동등 렌더가 FR-13 의 &quot;mermaid 동등 재현&quot; 요건. 플러그인이 코드펜스 문법을 그대로 받으므로 본문 변경 0.</li><li><strong>Alternatives considered</strong>: 다이어그램을 정적 이미지로 사전 렌더 → 유지보수 부담·소스 일관성 저하. 기각.</li></ul><h2 id="r-3-dead-link-strict-빌드-정책" tabindex="-1">R-3. Dead-link(strict) 빌드 정책 <a class="header-anchor" href="#r-3-dead-link-strict-빌드-정책" aria-label="Permalink to &quot;R-3. Dead-link(strict) 빌드 정책&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>config.mts</code> 에서 <code>ignoreDeadLinks</code> 를 설정하지 않는다(기본값). VitePress 는 기본적으로 죽은 내부 링크 발견 시 <strong>빌드를 실패</strong>시킨다.</li><li><strong>Rationale</strong>: spec Clarification = strict(빌드 실패) → 기본 동작이 정확히 일치. CI 가 그대로 게이트가 됨(FR-10/SC-6).</li><li><strong>Alternatives considered</strong>: <code>ignoreDeadLinks: true</code>(Docusaurus 의 warn 유사) → 결정과 반대. 기각. 특정 외부/의도적 링크만 정규식 예외 허용은 필요 시 국소 적용.</li></ul><h2 id="r-4-저널-인덱스-—-최근-먼저-자동-생성" tabindex="-1">R-4. 저널 인덱스 — &quot;최근 먼저&quot; 자동 생성 <a class="header-anchor" href="#r-4-저널-인덱스-—-최근-먼저-자동-생성" aria-label="Permalink to &quot;R-4. 저널 인덱스 — &quot;최근 먼저&quot; 자동 생성&quot;">​</a></h2><ul><li><strong>Decision</strong>: VitePress <strong>build-time data loader</strong>(<code>*.data.mts</code>, <code>createContentLoader</code> 또는 커스텀 <code>load()</code>)로 <code>journal/*.md</code> frontmatter 를 읽어 <code>created</code>(없으면 <code>date</code>) <strong>내림차순</strong> 정렬된 배열을 생성. <code>journal/index.md</code> 의 <code>&lt;script setup&gt;</code> 에서 <code>import { data } from &#39;../.vitepress/data/journal.data.mts&#39;</code> 로 받아 목록 렌더.</li><li><strong>Rationale</strong>: VitePress 엔 Docusaurus 같은 블로그 플러그인이 없다. data loader 는 빌드타임에 한 번 실행돼 정적 데이터로 번들 → 런타임 비용 0, 새 글 추가 시 자동 반영(SC-2). <code>created</code>(시간 포함) 규칙·&quot;최근 먼저&quot;(CLAUDE.md) 충족.</li><li><strong>Alternatives considered</strong>: <ul><li>수동 목록 → 누락 위험, Clarification 에서 기각됨.</li><li>서드파티 블로그 테마 → 참조 형태 이탈·의존성 증가, 기각됨.</li></ul></li></ul><h2 id="r-5-specs-사이드바-자동-생성" tabindex="-1">R-5. specs 사이드바 자동 생성 <a class="header-anchor" href="#r-5-specs-사이드바-자동-생성" aria-label="Permalink to &quot;R-5. specs 사이드바 자동 생성&quot;">​</a></h2><ul><li><strong>Decision</strong>: sync 스크립트가 <code>specs/</code> 를 스캔해 사이드바 JSON 을 생성하고, <code>config.mts</code> 가 그 파일을 import 한다. 정렬은 <strong>feature 번호 내림차순</strong>(큰 번호 먼저). <code>checklists/</code> 제외(현 sync 규칙 유지).</li><li><strong>Rationale</strong>: VitePress 사이드바는 정적 설정(수동)이 기본. sync 단계에서 생성하면 새 spec 추가 시 config 수기 편집 0(FR-6/SC-3). 동기화와 사이드바 생성을 한 스크립트에 두어 단일 소스(빌드 전 1회 실행).</li><li><strong>Alternatives considered</strong>: <ul><li>디렉터리 기반 자동 사이드바 플러그인 → 정렬(번호 내림차순) 커스터마이즈가 제한적이고 의존성 추가. sync 스크립트가 어차피 도므로 거기서 생성이 단순.</li></ul></li></ul><h2 id="r-6-github-pages-배포-base-artifact" tabindex="-1">R-6. GitHub Pages 배포 (base/artifact) <a class="header-anchor" href="#r-6-github-pages-배포-base-artifact" aria-label="Permalink to &quot;R-6. GitHub Pages 배포 (base/artifact)&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>base: &#39;/blog/&#39;</code> 유지. CI 의 upload-pages-artifact <code>path</code> 를 <code>blog/.vitepress/dist</code> 로 변경. 트리거 paths·sync 단계 스크립트명 갱신. node 24 로 정렬, <code>cache: npm</code> + <code>blog/package-lock.json</code>(신규 lockfile).</li><li><strong>Rationale</strong>: 리포 이름이 <code>blog</code> 라 Pages 경로가 <code>/blog/</code>(SC-1/FR-9). VitePress 산출물은 <code>.vitepress/dist</code>(Docusaurus <code>build/</code> 와 다름) → artifact 경로 교체 필수.</li><li><strong>Alternatives considered</strong>: 루트 <code>/</code> (사용자/조직 페이지·커스텀 도메인) → 기존 공개 URL 변경·기존 링크 파손. 기각(Clarification = <code>/blog/</code> 유지).</li></ul><h2 id="콘텐츠-인벤토리-이관-대상-실측" tabindex="-1">콘텐츠 인벤토리(이관 대상 실측) <a class="header-anchor" href="#콘텐츠-인벤토리-이관-대상-실측" aria-label="Permalink to &quot;콘텐츠 인벤토리(이관 대상 실측)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>수량/위치</th><th>정제 필요</th></tr></thead><tbody><tr><td>저널 글</td><td>12 (<code>blog/blog/*.md</code>)</td><td><code>{/* truncate */}</code> 제거(10), JSX 제거(1)</td></tr><tr><td>mermaid 사용 저널</td><td>3</td><td>플러그인으로 그대로 렌더</td></tr><tr><td>JSX/<code>&lt;VuGrid&gt;</code> 저널</td><td>1 (<code>vugrid-integration.md</code>)</td><td>정적화(FR-13)</td></tr><tr><td><code>:::</code> admonition</td><td>1 (<code>docs-pipeline.md</code>)</td><td>호환 — 수정 불요</td></tr><tr><td>specs 문서</td><td><code>specs/**/*.md</code>(checklists 제외)</td><td>sync 복사 + mermaid 렌더</td></tr><tr><td>정적 자산</td><td><code>blog/static/</code>, <code>vendor/vugrid</code></td><td>static→public 이전 검토 / vendor 분리</td></tr></tbody></table>',16)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
